14110   // If the value is not a vectorized instruction in the expression and not used
14111   // by the insertelement instruction and not used in multiple vector nodes, it
14112   // cannot be demoted.
14113   auto IsPotentiallyTruncated = [&](Value *V, unsigned &BitWidth) -> bool {
14114     if (MultiNodeScalars.contains(V))
14115       return false;
14116     uint32_t OrigBitWidth = DL->getTypeSizeInBits(V->getType());
14117     if (OrigBitWidth > BitWidth) {
14118       APInt Mask = APInt::getBitsSetFrom(OrigBitWidth, BitWidth);
14119       if (MaskedValueIsZero(V, Mask, SimplifyQuery(*DL)))
14120         return true;
14121     }
14122     auto NumSignBits = ComputeNumSignBits(V, *DL, 0, AC, nullptr, DT);
14123     unsigned BitWidth1 = OrigBitWidth - NumSignBits;
14124     if (!isKnownNonNegative(V, SimplifyQuery(*DL)))
14125       ++BitWidth1;
14126     BitWidth = std::max(BitWidth, BitWidth1);
14127     return BitWidth > 0 && OrigBitWidth >= (BitWidth * 2);
14128   };
14129   auto FinalAnalysis = [&](const TreeEntry *ITE = nullptr) {
14130     if (!IsProfitableToDemote)
14131       return false;
14132     return (ITE && ITE->UserTreeIndices.size() > 1) ||
14133            IsPotentiallyTruncated(V, BitWidth);
14134   };
14135   // TODO: improve handling of gathered values and others.
14136   auto *I = dyn_cast<Instruction>(V);
14137   const TreeEntry *ITE = I ? getTreeEntry(I) : nullptr;
14138   if (!ITE || !Visited.insert(I).second || MultiNodeScalars.contains(I) ||
14139       all_of(I->users(), [&](User *U) {
14140         return isa<InsertElementInst>(U) && !getTreeEntry(U);
