14143 
14144   unsigned Start = 0;
14145   unsigned End = I->getNumOperands();
14146 
14147   auto ProcessOperands = [&](ArrayRef<Value *> Operands, bool &NeedToExit) {
14148     NeedToExit = false;
14149     unsigned InitLevel = MaxDepthLevel;
14150     for (Value *IncValue : Operands) {
14151       unsigned Level = InitLevel;
14152       if (!collectValuesToDemote(IncValue, IsProfitableToDemoteRoot, BitWidth,
14153                                  ToDemote, DemotedConsts, Visited, Level,
14154                                  IsProfitableToDemote, IsTruncRoot)) {
14155         if (!IsProfitableToDemote)
14156           return false;
14157         NeedToExit = true;
14158         if (!FinalAnalysis(ITE))
